    triggerConfigImport(){document.getElementById('file-in')?.click();},
    readImportFile(file){
        return new Promise((resolve,reject)=>{
            const reader=new FileReader();
            reader.onload=event=>resolve(String(event?.target?.result||''));
            reader.onerror=()=>reject(new Error('读取配置文件失败'));
            reader.readAsText(file);
        });
    },
    normalizeImportedNodes(list){return(Array.isArray(list)?list:[]).map(item=>this.normalizeNode({name:String(item?.name||'').trim(),path:String(item?.path||item?.secret||item?.name||'').trim(),targets:item?.targets,target:item?.target,lines:item?.lines,activeLineId:item?.activeLineId,headers:item?.headers,remark:String(item?.remark||'').trim(),tags:item?.tags,tag:String(item?.tag||'').trim(),redirectWhitelistEnabled:item?.redirectWhitelistEnabled===true,playbackMode:item?.playbackMode,realClientIpMode:item?.realClientIpMode})).filter(item=>item.name&&item.path&&item.target);},
